class MarketProxyGroup {
  private _request: RequestFn;
  constructor(request: RequestFn) { this._request = request; }

  /**
   * Get Proxy
   * 
   * Gets your proxy list.
   * 
   * @http GET /proxy
   */
  async get(): Promise<ProxyGetResponse> {
    const path = "/proxy";
    const options: Record<string, unknown> = {};
    return this._request("GET", path, options) as Promise<ProxyGetResponse>;
  }

  /**
   * Add Proxy
   * 
   * Add single proxy or proxy list.
   * 
   * 
   * To add single proxy use this parameters:
   * 
   * 
   * + **proxy_ip** (required) - proxy ip or host
   * + **proxy_port** (required) - proxy port
   * + **proxy_user** (optional) - proxy username
   * + **proxy_pass** (optional) - proxy password
   * 
   * To add proxy list use this parameters:
   * 
   * 
   * + **proxy_row** (required) - proxy list in String format ip:port:user:pass. Each proxy must be start with new line (use \n separator)
   * 
   * @http POST /proxy
   */
  async add(body?: ProxyAddBody): Promise<ProxyAddResponse> {
    const path = "/proxy";
    const options: Record<string, unknown> = {};
    if (body) {
      const json: Record<string, unknown> = {};
      if (body.proxy_ip !== undefined) json["proxy_ip"] = body.proxy_ip;
      if (body.proxy_port !== undefined) json["proxy_port"] = body.proxy_port;
      if (body.proxy_user !== undefined) json["proxy_user"] = body.proxy_user;
      if (body.proxy_pass !== undefined) json["proxy_pass"] = body.proxy_pass;
      if (body.proxy_row !== undefined) json["proxy_row"] = body.proxy_row;
      if (Object.keys(json).length > 0) options.json = json;
    }
    return this._request("POST", path, options) as Promise<ProxyAddResponse>;
  }

  /**
   * Delete Proxy
   * 
   * Delete single or all proxies.
   * 
   * @http DELETE /proxy
   */
  async delete_(body?: ProxyDeleteBody): Promise<ProxyDeleteResponse> {
    const path = "/proxy";
    const options: Record<string, unknown> = {};
    if (body) {
      const json: Record<string, unknown> = {};
      if (body.proxy_id !== undefined) json["proxy_id"] = body.proxy_id;
      if (body.delete_all !== undefined) json["delete_all"] = body.delete_all ? "1" : "0";
      if (Object.keys(json).length > 0) options.json = json;
    }
    return this._request("DELETE", path, options) as Promise<ProxyDeleteResponse>;
  }

}

