class MarketBatchRequestsGroup {
  private _request: RequestFn;
  constructor(request: RequestFn) { this._request = request; }

  /**
   * Batch
   * 
   * Execute multiple API requests at once (separated by comma). Maximum batch jobs is 10.
   * Following methods are unavailable in Batch:
   * - GET /{item_id}/image
   * - /item/fast-sell
   * 
   * @http POST /batch
   */
  async batch(jobs: Array<{ id?: string; uri: string; method?: string; params?: Record<string, string> }>): Promise<BatchResponse> {
    const path = "/batch";
    const options: Record<string, unknown> = {};
    options.json = jobs;
    return this._request("POST", path, options) as Promise<BatchResponse>;
  }

}

